#include <iostream>

int main() {
    int* a = new int;
    int* b = new int;
    std::cin >> *a >> *b;

    // Swap the values
    int tmp = *a;
    *a = *b;
    *b = tmp;   // fixed: use tmp, not *a

    std::cout << "A: " << *a << "\n";
    std::cout << "B: " << *b << "\n";

    delete a;
    delete b;
    return 0;
}
